class Solution {
public:
    int addMinimum(string word) {
        int a_count = 0, c_count = 0;
        int b_pending = 0;
        for (char c : word) {
            if (c == 'a') {
                a_count++;
                b_pending = max(b_pending, a_count - c_count);
            } else if (c == 'b') {
                if (a_count > c_count) {
                    c_count++;
                } else {
                    b_pending++;
                    a_count++;
                }
            } else {
                c_count++;
            }
        }
        return b_pending * 2 + max(0, a_count - c_count);
    }
};
```
